const body = $input.item.json.body || {};
const text = String(body.content || '').trim();
let mode = String(body.mode || 'chat').toLowerCase();

if (mode === 'direct' || mode === 'direct_command' || mode === 'command') {
  mode = 'tool';
}

const history = Array.isArray(body.history) ? body.history : [];
const historyEntries = history
  .slice(-20)
  .map((h) => ({
    sender: String((h && h.sender) || ''),
    text: String((h && h.text) || ''),
    timestamp: String((h && h.timestamp) || ''),
    meta: (h && typeof h.meta === 'object' && h.meta) ? h.meta : {},
  }));

const contextState = (body.contextState && typeof body.contextState === 'object') ? body.contextState : {};
const internetSearchEnabled = body.internetSearchEnabled === true;

const historyText = historyEntries
  .map((h) => `${h.sender || 'unknown'}: ${h.text}`)
  .join('\n');

const DEFAULT_BASE_DIR = 'C:/Users/Martin/.n8n-files/Axiom_Files';

const cleanupPath = (raw) => {
  let p = String(raw || '').replace(/\\/g, '/').trim();
  p = p.replace(/^[\s"']+|[\s"']+$/g, '');
  p = p.replace(/[\]\)\}]+$/g, '');
  p = p.replace(/[.,;:!?]+$/g, '');
  return p;
};

const axiomBaseDir = cleanupPath(contextState.baseDir || body.baseDir || DEFAULT_BASE_DIR).replace(/[\\/]+$/, '');

const trimPathCandidate = (raw) => {
  let value = String(raw || '').trim().replace(/^['"`]+|['"`]+$/g, '');
  if (!value) return '';

  const fileToken = value.match(/^(.+?\.[A-Za-z0-9]{1,10})(?=$|\s|[),.;:!?])/);
  if (fileToken && fileToken[1]) return cleanupPath(fileToken[1]);

  value = value.replace(
    /\s+(?:with\s+text|with\s+content|with|and\s+text|text\s*(?:is|:)|then|please|named|called|name\s+it)\b[\s\S]*$/i,
    '',
  );
  const cleaned = cleanupPath(value).replace(/[\\/]+$/, '');
  if (!cleaned) return '';
  if (/^[A-Za-z]:$/.test(cleaned)) return '';
  if (axiomBaseDir && cleaned.toLowerCase() === axiomBaseDir.toLowerCase()) return '';
  if (/[\\/]Axiom_Files$/i.test(cleaned)) return '';
  return cleaned;
};

const pathRegex = /([A-Za-z]:[\\/][^\n\r]+)/g;

const extractPathCandidates = (msg) => {
  const source = String(msg || '');
  const out = [];

  const targetLine = source.match(/Target file path:\s*([^\n\r]+)/i);
  if (targetLine && targetLine[1]) out.push(trimPathCandidate(targetLine[1]));

  const quoted = [...source.matchAll(/["'`]([A-Za-z]:[\\/][^"'`\n\r]+)["'`]/g)];
  for (const m of quoted) {
    if (m && m[1]) out.push(trimPathCandidate(m[1]));
  }

  const commonInline = [...source.matchAll(/(?:file\s+to|path\s*:|at)\s*([A-Za-z]:[\\/][^\n\r]+)/gi)];
  for (const m of commonInline) {
    if (m && m[1]) out.push(trimPathCandidate(m[1]));
  }

  const generic = [...source.matchAll(pathRegex)];
  for (const m of generic) {
    if (m && m[1]) out.push(trimPathCandidate(m[1]));
  }

  return out.filter(Boolean);
};

const extractLastPath = (entries) => {
  for (let i = entries.length - 1; i >= 0; i--) {
    const entry = entries[i] || {};
    const meta = (entry.meta && typeof entry.meta === 'object') ? entry.meta : {};
    const metaState = (meta.contextState && typeof meta.contextState === 'object') ? meta.contextState : {};
    const metaPath = trimPathCandidate(meta.lastFilePath || meta.contextLastFilePath || metaState.lastFilePath || '');
    if (metaPath) return metaPath;

    const msg = entry.text || '';
    const matches = extractPathCandidates(msg);
    for (let j = matches.length - 1; j >= 0; j--) {
      const p = trimPathCandidate(matches[j] || '');
      if (p) return p;
    }
  }
  return '';
};

const fileIntentRegex = /\b(write|put|create|save|append|update|udpate|updte|updat|udate|edit|modify|add|make|build|generate|include|insert|format|transform|adjust|rename|renmae|move|delete|remove|erase|trash|read|open|show|list)\b[\s\S]*\b(file|txt|text|document|note|folder|directory|files?)\b/i;

const extractLastUserFileCommand = (entries) => {
  for (let i = entries.length - 1; i >= 0; i--) {
    const e = entries[i];
    if ((e.sender || '').toLowerCase() !== 'user') continue;
    if (fileIntentRegex.test(e.text || '')) return String(e.text || '').trim();
  }
  return '';
};

const readTextFileSafe = (absolutePath) => {
  try {
    const fs = require('fs');
    const p = cleanupPath(absolutePath);
    if (!p || !fs.existsSync(p)) return '';
    return String(fs.readFileSync(p, 'utf8') || '').slice(0, 5000);
  } catch (e) {
    return '';
  }
};

const getLastPendingClarify = (entries) => {
  for (let i = entries.length - 1; i >= 0; i--) {
    const entry = entries[i] || {};
    const meta = (entry.meta && typeof entry.meta === 'object') ? entry.meta : {};
    const state = (meta.contextState && typeof meta.contextState === 'object') ? meta.contextState : {};
    if (typeof state.pendingClarify === 'boolean') return state.pendingClarify;
    if (String(meta.contextPendingClarify || state.contextPendingClarify || '').trim() === '1') return true;
    if (String(meta.contextPendingClarify || state.contextPendingClarify || '').trim() === '0') return false;
  }
  return false;
};

const contextLastFilePath = cleanupPath(contextState.lastFilePath || contextState.contextLastFilePath || '');
const contextLastUserFileCommand = String(contextState.lastUserFileCommand || '').trim();
const lastFilePath = trimPathCandidate(contextLastFilePath || extractLastPath(historyEntries));
const lastUserFileCommand = contextLastUserFileCommand || extractLastUserFileCommand(historyEntries);
const pendingClarify =
  contextState.pendingClarify === true ||
  String(contextState.contextPendingClarify || '').trim() === '1' ||
  getLastPendingClarify(historyEntries) === true;

const shortFollowUp = /^\s*(do it|you do it|make it|please do it|i need you to make it|i need you top make it|just do it)\s*[.!?]*\s*$/i.test(text);
const optionSelectionMatch = text.match(/^\s*(?:option\s*)?(1|2|3|4)\s*$/i);

const lowerText = text.toLowerCase();
const lowerIntent = lowerText.replace(/"[^"]*"|'[^']*'|`[^`]*`/g, ' ');
const hasContextPronoun = /\b(it|this|that|same)\b/.test(lowerIntent);
const hasWriteVerb = /\b(write|put|add|append|update|udpate|updte|updat|udate|edit|modify|change|replace|rewrite|create|make|include|insert|format|transform|adjust|rename|renmae|move|delete|remove|erase|trash)\b/.test(lowerIntent);
const hasLineIntent = /\b(?:\d+(?:st|nd|rd|th)?[a-z]*|first|second|third|thrid|tird|fourth|fifth|sixth|seventh|eighth|ninth|tenth)\s+line\b/.test(lowerIntent);
const hasLatestFileReference = /\b(?:latest|last|previous|current)\s+(?:txt|text|file|document)\b/.test(lowerIntent);
const hasSpacingTransformIntent =
  /\b(?:space|spacing)\b.*\b(?:after|between)\b.*\b(?:each|every)\b.*\b(?:letter|character|char)\b/.test(lowerIntent) ||
  /\binclude\s+space\s+after\s+each\s+(?:letter|character|char)\b/.test(lowerIntent) ||
  /\bspace\s+out\s+(?:the\s+)?(?:letters|text)\b/.test(lowerIntent) ||
  /\bafter\s+each\s+(?:letter|character|char)\b[\s\S]*\b(?:add|insert|put|include)\b[\s\S]*\bspace\b/.test(lowerIntent) ||
  /\b(?:every|each)\s+(?:letter|character|char)\b[\s\S]*\bfollow\w*\b[\s\S]*\bspace\b/.test(lowerIntent) ||
  /\bblank\s+lines?\b[\s\S]*\bbetween\s+lines?\b/.test(lowerIntent) ||
  /\bbetween\s+words?\b[\s\S]*\bspace\b/.test(lowerIntent);
const hasReplaceIntent = /\breplace\b[\s\S]*\bwith\b/.test(lowerIntent);
const hasTransformFollowUp = hasSpacingTransformIntent || hasReplaceIntent;
const likelyInternetRequired = mode === 'chat' && (
  /\b(check|search|look\s*up|find)\b[\s\S]*\b(net|internet|online|web|news|latest|current)\b/.test(lowerIntent) ||
  /\b(latest|today|current|real[-\s]?time|up[-\s]?to[-\s]?date)\b/.test(lowerIntent) ||
  /\b(news|headline|price|stock|weather|forecast|score|results|trend|market)\b/.test(lowerIntent)
);
const isCreateWithName = /\b(create|make|build|generate|new)\b/.test(lowerIntent) && /\b(name\s+it|named|called|filename|file\s+name)\b/.test(lowerIntent);

let normalizedContent = text;

if (mode === 'tool' && shortFollowUp && lastUserFileCommand) {
  normalizedContent = lastUserFileCommand;
}

if (mode === 'tool' && optionSelectionMatch && lastUserFileCommand) {
  normalizedContent = `${lastUserFileCommand}\n\nSelection: ${optionSelectionMatch[1]}`;
}

const needsContextBinding = !!lastFilePath && (
  /\b(that|this|same)\s+file\b/.test(lowerIntent) ||
  /\b(?:in|into)\s+it\b/.test(lowerIntent) ||
  hasLatestFileReference ||
  (hasContextPronoun && hasWriteVerb && !isCreateWithName) ||
  hasLineIntent ||
  hasTransformFollowUp ||
  (!!optionSelectionMatch && mode === 'tool')
);

if (needsContextBinding) {
  if (!/Target file path:/i.test(normalizedContent)) {
    normalizedContent += `\n\nTarget file path: ${lastFilePath}`;
  }
  const currentFileContent = readTextFileSafe(lastFilePath);
  if (currentFileContent) {
    normalizedContent += `\n\nCurrent file content:\n${currentFileContent}`;
  }
}

const toolIntent = [
  /\b(write|put|create|save|append|update|udpate|updte|updat|udate|edit|modify|add|make|build|generate|include|insert|format|transform|adjust|rename|renmae|move|delete|remove|erase|trash)\b.*\b(file|txt|text|document|note)\b/,
  /\b(read|open|show)\b.*\b(file|txt|text|document|note)\b/,
  /\b(list|show)\b.*\b(directory|folder|files?)\b/,
  /\b(make|create)\b.*\b(folder|directory)\b/,
  /\b(that|this|same)\s+file\b/,
  /\b(?:in|into)\s+it\b/,
  /\b(?:latest|last|previous|current)\s+(?:txt|text|file|document)\b/,
  /\bmake\s+me\b.*\b(txt|file)\b/,
  /\bhello\s+world\b.*\b(txt|file)\b/,
].some((r) => r.test(normalizedContent.toLowerCase().replace(/"[^"]*"|'[^']*'|`[^`]*`/g, ' ')));

const explicitSelection = /^\s*(?:option\s*)?[1-4]\s*$/i.test(text);
const contextualFileFollowUp = !!lastFilePath && (
  ((/\b(it|this|that|same)\b/.test(lowerIntent) || /\b(?:in|into)\s+it\b/.test(lowerIntent) || hasLatestFileReference) && hasWriteVerb) ||
  hasLineIntent ||
  hasTransformFollowUp ||
  /^\s*text\s+is\b/.test(lowerIntent) ||
  /^\s*insert\b/.test(lowerIntent) ||
  /^\s*add\b/.test(lowerIntent) ||
  /^\s*replace\b/.test(lowerIntent)
);

let chatExecutionGuard = false;
let chatGuardMessage = '';
if (mode === 'chat' && (toolIntent || shortFollowUp || contextualFileFollowUp || (explicitSelection && !!lastUserFileCommand))) {
  chatExecutionGuard = true;
  chatGuardMessage = 'This looks like a file/tool operation. Switch to Direct Command to run it safely.';
}

if (mode === 'chat' && !internetSearchEnabled && likelyInternetRequired) {
  chatExecutionGuard = true;
  chatGuardMessage = 'This request likely needs live internet data. Enable Internet search (globe button, tooltip: "Internet search") and resend.';
}

return {
  json: {
    mode,
    rawContent: text,
    content: normalizedContent,
    historyText,
    lastFilePath,
    lastUserFileCommand,
    pendingClarify,
    internetSearchEnabled,
    internetRequiredButDisabled: (!internetSearchEnabled && likelyInternetRequired),
    chatExecutionGuard,
    chatGuardMessage,
    contextState: {
      ...contextState,
      lastFilePath,
      lastUserFileCommand,
      pendingClarify,
      contextPendingClarify: pendingClarify ? '1' : '0',
    },
  },
};

const text = String($json.content ?? '');
const fileName = String(($json.fullPath || 'output.txt').split('/').pop() || 'output.txt');

return {
  json: $json,
  binary: {
    content: {
      data: Buffer.from(text, 'utf8').toString('base64'),
      mimeType: 'text/plain',
      fileName,
    },
  },
};

const isPlan = String($json.routeMode || '') === 'plan';
if (isPlan) {
  return { json: { ...$json, status: 'clarify', action: 'clarify', error: '', traceId: $json.traceId || 'no-trace', response: 'Plan review required before execution:

' + String($json.planReadable || '[ACTION: CHANGE]
[TARGET: unresolved]
[USING: clarify]') + '

Open Plan Builder (or switch to Direct Command with explicit confirmation) to run.' } };
}
return { json: { ...$json, status: 'error', action: 'error', error: $json.message || 'Unable to resolve safe action', traceId: $json.traceId || 'no-trace', response: String($json.message || 'Unable to resolve a safe action. Please specify: read file, write file with content, or list directory.') } };

const fs = require('fs');
const baseDir = 'C:/Users/Martin/.n8n-files/Axiom_Files';
const drive = (String(baseDir).match(/^([A-Za-z]):\//) || [null, 'C'])[1];
const normalizePath = (raw) => {
  let p = String(raw || '').trim().replace(/\\/g, '/');
  if (/^\/Users\//i.test(p)) p = `${drive}:${p}`;
  return p;
};
const fullPath = normalizePath($json.fullPath || $json.path || '');
const fileLabel = $json.fileName ? ` (${String($json.fileName)})` : (fullPath ? ` (${fullPath})` : '');

if (!fullPath) {
  return { json: { ...$json, status: 'error', action: $json.action || 'read_file', error: 'Missing file path.', traceId: $json.traceId || 'no-trace', response: 'I need a file path to read.' } };
}

if (!fs.existsSync(fullPath)) {
  return { json: { ...$json, status: 'error', action: $json.action || 'read_file', error: `File not found: ${fullPath}`, traceId: $json.traceId || 'no-trace', response: `I couldn't find file ${fullPath}.` } };
}

try {
  const stats = fs.statSync(fullPath);
  if (stats.isDirectory()) {
    return { json: { ...$json, status: 'error', action: $json.action || 'read_file', error: `Path is a directory: ${fullPath}`, traceId: $json.traceId || 'no-trace', response: `${fullPath} is a directory. Ask me to list directory instead.` } };
  }
  if (stats.size === 0) {
    return { json: { ...$json, status: 'success', action: $json.action || 'read_file', error: '', traceId: $json.traceId || 'no-trace', response: `File ${fullPath} is empty.` } };
  }
} catch (e) {
  return { json: { ...$json, status: 'error', action: $json.action || 'read_file', error: `Unable to stat file: ${fullPath}`, traceId: $json.traceId || 'no-trace', response: `I could not inspect file ${fullPath}.` } };
}

let content = '';
try {
  const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
  content = buffer.toString('utf8');
} catch (e) {
  content = '';
}
if (!content && typeof $json.data === 'string') content = String($json.data);

if (!content) {
  return { json: { ...$json, status: 'error', action: $json.action || 'read_file', error: 'Unreadable file content.', traceId: $json.traceId || 'no-trace', response: `I could not read content from ${fullPath}.` } };
}

return { json: { ...$json, status: 'success', action: $json.action || 'read_file', error: '', traceId: $json.traceId || 'no-trace', fullPath, path: fullPath, response: `File Contents${fileLabel}:\n\n${content}` } };

const content = String($json.content || '');
const lower = content.toLowerCase();

const evalSummary = {
  hasFollowUpRef: /\b(it|this|that|same|latest|last|previous|current)\b/.test(lower),
  hasActionVerb: /\b(write|put|add|append|update|edit|modify|change|replace|rewrite|read|open|list|create|make|include|insert|format|transform|adjust)\b/.test(lower),
  hasExplicitPath: /[A-Za-z]:[\\/]/.test(content),
  mentionsFile: /\b(file|txt|text|document|folder|directory)\b/.test(lower),
  modeBeforeRouter: String($json.mode || ''),
};

return {
  json: {
    ...$json,
    inputEvaluation: evalSummary,
  },
};

const fs = require('fs');
const originalCommand = String($node['Extract Input'].json.content || '');
const lowerCommand = originalCommand.toLowerCase();
const fullPath = String($json.fullPath || $json.fileName || $json.path || '').replace(/\\/g, '/');
const sourcePath = String($json.sourcePath || '').replace(/\\/g, '/');
const destinationPath = String($json.destinationPath || '').replace(/\\/g, '/');
const plannedContent = String($json.content ?? '');
const action = String($json.action || '');
const allowEmptyWrite = $json.allowEmptyWrite === true;
const allowEmptyContent = allowEmptyWrite || $json.postReadTransformApplied === true;

const fail = (reason, mode = action || 'unknown') => ({
  json: {
    ...$json,
    verification: {
      ok: false,
      reason,
      checkedPath: fullPath || destinationPath || sourcePath,
      mode,
      verifiedBy: 'strict-runtime',
    },
  },
});

const ok = (extra = {}) => ({
  json: {
    ...$json,
    verification: {
      ok: true,
      reason: 'ok',
      checkedPath: fullPath || destinationPath || sourcePath,
      mode: action || 'unknown',
      verifiedBy: 'strict-runtime',
      ...extra,
    },
  },
});

if (action === 'write_file') {
  if (!fullPath) return fail('Missing target file path', 'write');
  if (!fs.existsSync(fullPath)) return fail('Write target does not exist after write', 'write');

  const stats = fs.statSync(fullPath);
  if (!stats.isFile()) return fail('Write target is not a file', 'write');

  if (allowEmptyWrite) {
    if (stats.size !== 0) return fail('Expected empty file but file has content', 'write');
    return ok();
  }

  if (!allowEmptyContent && !plannedContent.trim()) {
    return fail('Write plan has empty content', 'write');
  }

  let actualContent = '';
  try {
    actualContent = String(fs.readFileSync(fullPath, 'utf8') || '');
  } catch (e) {
    return fail('Could not read written file for verification', 'write');
  }

  if (!$json.postReadTransformApplied && plannedContent !== '' && actualContent !== plannedContent) {
    return fail('Written content does not match planned content', 'write');
  }

  const isSpaceIntent = /\b(?:space|spacing)\b.*\b(?:after|between)\b.*\b(?:each|every)\b.*\b(?:letter|character|char)\b/.test(lowerCommand)
    || /\binclude\s+space\s+after\s+each\s+(?:letter|character|char)\b/.test(lowerCommand)
    || /\bspace\s+out\s+(?:the\s+)?(?:letters|text)\b/.test(lowerCommand);

  if (isSpaceIntent) {
    const letters = (actualContent.match(/[A-Za-z]/g) || []).length;
    const spaced = (actualContent.match(/[A-Za-z] /g) || []).length;
    const ratio = letters > 0 ? (spaced / letters) : 0;
    const ratioOk = letters > 0 && ratio >= 0.85;
    if (!ratioOk) return fail('Space-after-each-letter transform verification failed', 'write');
    return ok({ ratio });
  }

  return ok();
}

if (action === 'delete_file') {
  if (!fullPath) return fail('Missing target file path', 'delete');
  if (fs.existsSync(fullPath)) return fail('Delete verification failed: file still exists', 'delete');
  return ok();
}

if (action === 'move_file') {
  const src = sourcePath || fullPath;
  const dst = destinationPath || fullPath;
  if (!src || !dst) return fail('Missing source or destination path', 'move');
  if (src.toLowerCase() === dst.toLowerCase()) return fail('Source and destination are the same', 'move');
  if (!fs.existsSync(dst)) return fail('Move verification failed: destination missing', 'move');
  if (sourcePath && fs.existsSync(sourcePath)) return fail('Move verification failed: source still exists', 'move');
  return ok();
}

return ok({ verifiedBy: 'plan' });

const response = String($json.response || '').trim();
if (!response) {
  return { json: { ...$json, response: ($json.message ? String($json.message) : 'Workflow completed, but no response payload was generated.') } };
}
return { json: { ...$json, response } };

const originalCommand = String($node["Extract Input"].json.content || '').toLowerCase();
const spaceIntent =
  /\b(?:space|spacing)\b.*\b(?:after|between)\b.*\b(?:each|every)\b.*\b(?:letter|character|char)\b/.test(originalCommand) ||
  /\binclude\s+space\s+after\s+each\s+(?:letter|character|char)\b/.test(originalCommand) ||
  /\bspace\s+out\s+(?:the\s+)?(?:letters|text)\b/.test(originalCommand) ||
  /\bafter\s+each\s+(?:letter|character|char)\b[\s\S]*\b(?:add|insert|put|include)\b[\s\S]*\bspace\b/.test(originalCommand) ||
  /\b(?:every|each)\s+(?:letter|character|char)\b[\s\S]*\bfollow\w*\b[\s\S]*\bspace\b/.test(originalCommand);

let plan = $node["Parse JSON"].json.postReadTransform;
if (!plan && spaceIntent) {
  plan = { type: 'space_letters' };
}

if (plan && plan.type === 'line_edit' && Array.isArray(plan.lineEdits)) {
  plan = {
    ...plan,
    lineEdits: plan.lineEdits
      .map((e) => {
        const raw = String((e && e.text) || '');
        const q = raw.match(/"([^"]+)"/) || raw.match(/'([^']+)'/);
        let text = q ? q[1] : raw;
        text = text.replace(/^\s*(?:text|line|content)\s*(?::|is)?\s*/i, '');
        text = text.replace(/^\s*(?:is|to|should\s+be|should\s+say|it\s+is|it\s+says?|says?)\s*/i, '').trim();
        text = text.replace(/^['"]|['"]$/g, '').trim();
        return { line: Number((e && e.line) || 0), text };
      })
      .filter((e) => Number.isFinite(e.line) && e.line > 0 && e.text.length > 0),
  };
}

const fullPath = String($node["Parse JSON"].json.fullPath || $json.fullPath || $json.path || '').replace(/\\/g, '/');

return {
  json: {
    ...$json,
    fullPath,
    path: fullPath || $json.path || '',
    postReadTransform: plan,
  },
  binary: $binary,
};

const fs = require('fs');
const baseDir = 'C:/Users/Martin/.n8n-files/Axiom_Files';
const drive = (String(baseDir).match(/^([A-Za-z]):\//) || [null, 'C'])[1];
const normalizePath = (raw) => {
  let p = String(raw || '').trim().replace(/\\/g, '/');
  if (/^\/Users\//i.test(p)) p = `${drive}:${p}`;
  return p;
};
const fullPath = normalizePath($json.fullPath || $json.path || '');
if (!fullPath) throw new Error('Missing file path for delete operation.');
if (!fs.existsSync(fullPath)) throw new Error('File not found: ' + fullPath);
fs.unlinkSync(fullPath);
return {
  json: {
    ...$json,
    action: 'delete_file',
    fullPath,
    path: fullPath,
    deleteResult: 'deleted',
  },
};

const fs = require('fs');
const path = require('path');
const baseDir = 'C:/Users/Martin/.n8n-files/Axiom_Files';
const drive = (String(baseDir).match(/^([A-Za-z]):\//) || [null, 'C'])[1];
const normalizePath = (raw) => {
  let p = String(raw || '').trim().replace(/\\/g, '/');
  if (/^\/Users\//i.test(p)) p = `${drive}:${p}`;
  return p;
};
const sourcePath = normalizePath($json.fullPath || $json.path || '');
const destinationPath = normalizePath($json.destinationPath || '');
if (!sourcePath) throw new Error('Missing source path for move operation.');
if (!destinationPath) throw new Error('Missing destination path for move operation.');
if (sourcePath.toLowerCase() === destinationPath.toLowerCase()) throw new Error('Source and destination paths are the same.');
if (!fs.existsSync(sourcePath)) throw new Error('Source file not found: ' + sourcePath);
fs.mkdirSync(path.dirname(destinationPath), { recursive: true });
fs.renameSync(sourcePath, destinationPath);
return {
  json: {
    ...$json,
    action: 'move_file',
    sourcePath,
    destinationPath,
    fullPath: destinationPath,
    path: destinationPath,
    moveResult: 'moved',
  },
};

const rawQuery = String($node["Extract Input"].json.content || $json.content || '').trim();
const query = rawQuery.slice(0, 240);
const empty = { provider: 'google', query, snippets: [], heading: '', sourceUrls: [] };
const internetSearchEnabled = $node["Extract Input"].json.internetSearchEnabled === true;
if (!internetSearchEnabled) {
  return {
    json: {
      ...$json,
      webSearch: { provider: 'disabled', query: '', snippets: [], heading: '', sourceUrls: [] },
      webSearchDisabled: true,
    },
  };
}
if (!query) {
  return { json: { ...$json, webSearch: empty } };
}

const pushSnippet = (out, text, url) => {
  const t = String(text || '').replace(/\s+/g, ' ').trim();
  const u = String(url || '').trim();
  if (!t) return;
  if (out.some((s) => s.text === t)) return;
  out.push({ text: t.slice(0, 320), url: u });
};

const stripHtml = (html) => String(html || '')
  .replace(/<script[\s\S]*?<\/script>/gi, ' ')
  .replace(/<style[\s\S]*?<\/style>/gi, ' ')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/gi, ' ')
  .replace(/&amp;/gi, '&')
  .replace(/\s+/g, ' ')
  .trim();

const collectDdgTopics = (items, out) => {
  if (!Array.isArray(items)) return;
  for (const item of items) {
    if (Array.isArray(item?.Topics)) {
      collectDdgTopics(item.Topics, out);
      continue;
    }
    pushSnippet(out, item?.Text, item?.FirstURL);
    if (out.length >= 6) return;
  }
};

const tryGoogleProgrammable = async () => {
  const apiKey = String($env.GOOGLE_CSE_API_KEY || $env.AXIOM_GOOGLE_CSE_API_KEY || '').trim();
  const cx = String($env.GOOGLE_CSE_CX || $env.AXIOM_GOOGLE_CSE_CX || '').trim();
  if (!apiKey || !cx) return null;

  const url = `https://www.googleapis.com/customsearch/v1?num=6&safe=off&key=${encodeURIComponent(apiKey)}&cx=${encodeURIComponent(cx)}&q=${encodeURIComponent(query)}`;
  const res = await fetch(url, { method: 'GET', headers: { Accept: 'application/json' } });
  if (!res.ok) return null;

  const data = await res.json();
  const snippets = [];
  const items = Array.isArray(data?.items) ? data.items : [];
  for (const item of items) {
    pushSnippet(snippets, item?.snippet, item?.link);
    if (snippets.length >= 6) break;
  }

  if (!snippets.length) return null;
  return {
    provider: 'google',
    query,
    heading: String(data?.queries?.request?.[0]?.searchTerms || data?.context?.title || ''),
    snippets: snippets.slice(0, 6),
    sourceUrls: snippets.map((s) => s.url).filter(Boolean).slice(0, 6),
  };
};

const tryGoogleHtml = async () => {
  const url = `https://www.google.com/search?hl=en&num=6&q=${encodeURIComponent(query)}`;
  const res = await fetch(url, {
    method: 'GET',
    headers: {
      Accept: 'text/html',
      'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/124.0.0.0 Safari/537.36',
    },
  });
  if (!res.ok) return null;

  const html = await res.text();
  const snippets = [];
  const regex = /<a href="\/url\?q=([^"&]+)[^\"]*"[\s\S]*?<h3[^>]*>([\s\S]*?)<\/h3>[\s\S]*?(?:<div[^>]*class="[^"]*VwiC3b[^"]*"[^>]*>([\s\S]*?)<\/div>|<span[^>]*>([\s\S]*?)<\/span>)/gi;
  let match;
  while ((match = regex.exec(html)) !== null && snippets.length < 6) {
    let link = String(match[1] || '');
    try { link = decodeURIComponent(link.replace(/\+/g, '%20')); } catch {}
    const title = stripHtml(match[2] || '');
    const body = stripHtml(match[3] || match[4] || '');
    const text = [title, body].filter(Boolean).join(' - ');
    pushSnippet(snippets, text, link);
  }

  if (!snippets.length) return null;
  return {
    provider: 'google',
    query,
    heading: '',
    snippets: snippets.slice(0, 6),
    sourceUrls: snippets.map((s) => s.url).filter(Boolean).slice(0, 6),
  };
};

const tryDuckDuckGoFallback = async () => {
  const url = `https://api.duckduckgo.com/?format=json&no_html=1&skip_disambig=1&q=${encodeURIComponent(query)}`;
  const res = await fetch(url, { method: 'GET', headers: { Accept: 'application/json' } });
  const raw = await res.text();
  let data = {};
  try { data = JSON.parse(raw); } catch {}

  const snippets = [];
  pushSnippet(snippets, data?.AbstractText, data?.AbstractURL);
  collectDdgTopics(data?.RelatedTopics, snippets);
  if (!snippets.length) return null;

  return {
    provider: 'duckduckgo_fallback',
    query,
    heading: String(data?.Heading || ''),
    snippets: snippets.slice(0, 6),
    sourceUrls: snippets.map((s) => s.url).filter(Boolean).slice(0, 6),
  };
};

try {
  const cseResult = await tryGoogleProgrammable();
  if (cseResult) {
    return { json: { ...$json, webSearch: cseResult } };
  }

  const htmlResult = await tryGoogleHtml();
  if (htmlResult) {
    return { json: { ...$json, webSearch: htmlResult } };
  }

  const fallbackResult = await tryDuckDuckGoFallback();
  if (fallbackResult) {
    return { json: { ...$json, webSearch: fallbackResult } };
  }

  return {
    json: {
      ...$json,
      webSearch: empty,
      webSearchError: 'google_no_results',
    },
  };
} catch (error) {
  return {
    json: {
      ...$json,
      webSearch: empty,
      webSearchError: String(error?.message || error || 'web_search_failed'),
    },
  };
}

const search = ($json.webSearch && typeof $json.webSearch === 'object') ? $json.webSearch : {};
const snippets = Array.isArray(search.snippets) ? search.snippets : [];
const lines = [];

if (search.heading) {
  lines.push('Heading: ' + String(search.heading));
}

for (let i = 0; i < snippets.length && i < 4; i++) {
  const s = snippets[i] || {};
  const text = String(s.text || '').trim();
  const url = String(s.url || '').trim();
  if (!text) continue;
  lines.push((i + 1) + '. ' + text + (url ? (' (' + url + ')') : ''));
}

const providerRaw = String(search.provider || 'google').trim().toLowerCase();
const providerLabel = providerRaw === 'duckduckgo_fallback'
  ? 'Google unavailable, DuckDuckGo fallback'
  : (providerRaw === 'google' ? 'Google' : providerRaw);

const webContext = lines.length
  ? (providerLabel + ' results for "' + String(search.query || '').trim() + '":\n' + lines.join('\n'))
  : '';

return {
  json: {
    ...$json,
    webContext,
  },
};
